'use strict';(function(){const b={cache:!0};b.doc={id:'id',field:['title','content'],store:['title','href','section']};const a=FlexSearch.create('balance',b);window.bookSearchIndex=a,a.add({id:0,href:'/leetcode-js/ChapterOne/',title:"第一章 LeetCode 题解",section:"序",content:"第一章 LeetCode 题解 #  这一章就是 LeetCode 的题解了，还在慢慢更新中，欢迎大家提出更好的解法。点击页面下方的 edit，会跳转到 github 对应的页面 markdown 中，可以提交你的最优解 PR。\n ⬅️上一章\n下一页➡️\n "}),a.add({id:1,href:'/leetcode-js/ChapterOne/0001~0099/0001.Two-Sum/',title:"0001. Two Sum",section:"0001 0099",content:"1. Two Sum #  题目 #  Given an array of integers, return indices of the two numbers such that they add up to a specific target.\nYou may assume that each input would have exactly one solution, and you may not use the same element twice.\nExample:\n Given nums = [2, 7, 11, 15], target = 9, Because nums[0] + nums[1] = 2 + 7 = 9, return [0, 1] 题目大意 #  在数组中找到 2 个数之和等于给定值的数字，结果返回 2 个数字在数组中的下标。\n解题思路 #  这道题最优的做法时间复杂度是 O(n)。\n顺序扫描数组，对每一个元素，在 object 中找能组合给定值的另一半数字，如果找到了，直接返回 2 个数字的下标即可。如果找不到，就把这个数字存入 object 中，等待扫到“另一半”数字的时候，再取出来返回结果。\n代码 #  var twoSum = function(nums, target) { const numsObj = {} for(i = 0; i \u0026lt; nums.length; i ++) { const another = target - nums[i] if(another in numsObj) { return [numsObj[another], i] } numsObj[nums[i]] = i } };  ⬅️ 上一页\n下一页 ➡️\n "}),a.add({id:2,href:'/leetcode-js/ChapterOne/0001~0099/0002.Add-Two-Numbers/',title:"0002. Add Two Numbers",section:"0001 0099",content:"2. Add Two Numbers #  题目 #  You are given two non-empty linked lists representing two non-negative integers. The digits are stored in reverse order and each of their nodes contain a single digit. Add the two numbers and return it as a linked list.\nYou may assume the two numbers do not contain any leading zero, except the number 0 itself.\nExample:\n Input: (2 -\u0026gt; 4 -\u0026gt; 3) + (5 -\u0026gt; 6 -\u0026gt; 4) Output: 7 -\u0026gt; 0 -\u0026gt; 8 Explanation: 342 + 465 = 807. 题目大意 #  2 个逆序的链表，要求从低位开始相加，得出结果也逆序输出，返回值是逆序结果链表的头结点。\n解题思路 #  需要注意的是各种进位问题。\n极端情况，例如\n Input: (9 -\u0026gt; 9 -\u0026gt; 9 -\u0026gt; 9 -\u0026gt; 9) + (1 -\u0026gt; ) Output: 0 -\u0026gt; 0 -\u0026gt; 0 -\u0026gt; 0 -\u0026gt; 0 -\u0026gt; 1 为了处理方法统一，可以先建立一个虚拟头结点，这个虚拟头结点的 Next 指向真正的 head，这样 head 不需要单独处理，直接 while 循环即可。另外判断循环终止的条件不用是 p.Next ！= nil，这样最后一位还需要额外计算，循环终止条件应该是 p != nil。\n代码 #  /** * Definition for singly-linked list. * function ListNode(val) { * this.val = val; * this.next = null; * } */ /** * @param {ListNode} l1 * @param {ListNode} l2 * @return {ListNode} */ var addTwoNumbers = function(l1, l2) { var List = new ListNode(0); var head = List; var sum = 0; var carry = 0; while(l1!==null||l2!==null||sum\u0026gt;0){ if(l1!==null){ sum = sum + l1.val; l1 = l1.next; } if(l2!==null){ sum = sum + l2.val; l2 = l2.next; } if(sum\u0026gt;=10){ carry = 1; sum = sum - 10; } head.next = new ListNode(sum); head = head.next; sum = carry; carry = 0; } return List.next; };  ⬅️上一页\n下一页➡️\n "}),a.add({id:3,href:'/leetcode-js/ChapterOne/0001~0099/0003.Longest-Substring-Without-Repeating-Characters/',title:"0003. Longest Substring Without Repeating Characters",section:"0001 0099",content:"3. Longest Substring Without Repeating Characters #  题目 #  Given a string, find the length of the longest substring without repeating characters.\nExample 1:\n Input: \u0026quot;abcabcbb\u0026quot; Output: 3 Explanation: The answer is \u0026quot;abc\u0026quot;, with the length of 3. Example 2:\n Input: \u0026quot;bbbbb\u0026quot; Output: 1 Explanation: The answer is \u0026quot;b\u0026quot;, with the length of 1. Example 3:\n Input: \u0026quot;pwwkew\u0026quot; Output: 3 Explanation: The answer is \u0026quot;wke\u0026quot;, with the length of 3. Note that the answer must be a substring, \u0026quot;pwke\u0026quot; is a subsequence and not a substring. 题目大意 #  在一个字符串重寻找没有重复字母的最长子串。\n解题思路 #  这一题和第 438 题，第 3 题，第 76 题，第 567 题类似，用的思想都是\u0026quot;滑动窗口\u0026quot;。\n滑动窗口的右边界不断的右移，只要没有重复的字符，就持续向右扩大窗口边界。一旦出现了重复字符，就需要缩小左边界，直到重复的字符移出了左边界，然后继续移动滑动窗口的右边界。以此类推，每次移动需要计算当前长度，并判断是否需要更新最大长度，最终最大的值就是题目中的所求。\n代码 #  /** * @param {string} s * @return {number} */ var lengthOfLongestSubstring = function(s) { let max = 0; let curStr = \u0026#39;\u0026#39;; for (let i = 0; i \u0026lt; s.length; i++) { const char = s.charAt(i); const pos = curStr.indexOf(char); if (pos !== -1) { curStr = curStr.slice(pos + 1, curStr.length) } curStr += char max = Math.max(max, curStr.length) } return max; };  ⬅️上一页\n下一页➡️\n "}),a.add({id:4,href:'/leetcode-js/ChapterOne/0001~0099/0004.Median-of-Two-Sorted-Arrays/',title:"0004. Median of Two Sorted Arrays",section:"0001 0099",content:"4. Median of Two Sorted Arrays #  题目 #  There are two sorted arrays nums1 and nums2 of size m and n respectively.\nFind the median of the two sorted arrays. The overall run time complexity should be O(log (m+n)).\nYou may assume nums1 and nums2 cannot be both empty.\nExample 1:\nnums1 = [1, 3] nums2 = [2] The median is 2.0  Example 2:\nnums1 = [1, 2] nums2 = [3, 4] The median is (2 + 3)/2 = 2.5  题目大意 #  给定两个大小为 m 和 n 的有序数组 nums1 和 nums2。\n请你找出这两个有序数组的中位数，并且要求算法的时间复杂度为 O(log(m + n))。\n你可以假设 nums1 和 nums2 不会同时为空。\n解题思路 #    给出两个有序数组，要求找出这两个数组合并以后的有序数组中的中位数。要求时间复杂度为 O(log (m+n))。\n  这一题最容易想到的办法是把两个数组合并，然后取出中位数。但是合并有序数组的操作是 O(m+n) 的，不符合题意。看到题目给的 log 的时间复杂度，很容易联想到二分搜索。\n  由于要找到最终合并以后数组的中位数，两个数组的总大小也知道，所以中间这个位置也是知道的。只需要二分搜索一个数组中切分的位置，另一个数组中切分的位置也能得到。为了使得时间复杂度最小，所以二分搜索两个数组中长度较小的那个数组。\n  关键的问题是如何切分数组 1 和数组 2 。其实就是如何切分数组 1 。先随便二分产生一个 midA，切分的线何时算满足了中位数的条件呢？即，线左边的数都小于右边的数，即，nums1[midA-1] ≤ nums2[midB] \u0026amp;\u0026amp; nums2[midB-1] ≤ nums1[midA] 。如果这些条件都不满足，切分线就需要调整。如果 nums1[midA] \u0026lt; nums2[midB-1]，说明 midA 这条线划分出来左边的数小了，切分线应该右移；如果 nums1[midA-1] \u0026gt; nums2[midB]，说明 midA 这条线划分出来左边的数大了，切分线应该左移。经过多次调整以后，切分线总能找到满足条件的解。\n  假设现在找到了切分的两条线了，数组 1 在切分线两边的下标分别是 midA - 1 和 midA。数组 2 在切分线两边的下标分别是 midB - 1 和 midB。最终合并成最终数组，如果数组长度是奇数，那么中位数就是 max(nums1[midA-1], nums2[midB-1])。如果数组长度是偶数，那么中间位置的两个数依次是：max(nums1[midA-1], nums2[midB-1]) 和 min(nums1[midA], nums2[midB])，那么中位数就是 (max(nums1[midA-1], nums2[midB-1]) + min(nums1[midA], nums2[midB])) / 2。图示见下图：\n   代码 #  package leetcode func findMedianSortedArrays(nums1 []int, nums2 []int) float64 { // 假设 nums1 的长度小 	if len(nums1) \u0026gt; len(nums2) { return findMedianSortedArrays(nums2, nums1) } low, high, k, nums1Mid, nums2Mid := 0, len(nums1), (len(nums1)+len(nums2)+1)\u0026gt;\u0026gt;1, 0, 0 for low \u0026lt;= high { // nums1: ……………… nums1[nums1Mid-1] | nums1[nums1Mid] …………………… 	// nums2: ……………… nums2[nums2Mid-1] | nums2[nums2Mid] …………………… 	nums1Mid = low + (high-low)\u0026gt;\u0026gt;1 // 分界限右侧是 mid，分界线左侧是 mid - 1 	nums2Mid = k - nums1Mid if nums1Mid \u0026gt; 0 \u0026amp;\u0026amp; nums1[nums1Mid-1] \u0026gt; nums2[nums2Mid] { // nums1 中的分界线划多了，要向左边移动 	high = nums1Mid - 1 } else if nums1Mid != len(nums1) \u0026amp;\u0026amp; nums1[nums1Mid] \u0026lt; nums2[nums2Mid-1] { // nums1 中的分界线划少了，要向右边移动 	low = nums1Mid + 1 } else { // 找到合适的划分了，需要输出最终结果了 	// 分为奇数偶数 2 种情况 	break } } midLeft, midRight := 0, 0 if nums1Mid == 0 { midLeft = nums2[nums2Mid-1] } else if nums2Mid == 0 { midLeft = nums1[nums1Mid-1] } else { midLeft = max(nums1[nums1Mid-1], nums2[nums2Mid-1]) } if (len(nums1)+len(nums2))\u0026amp;1 == 1 { return float64(midLeft) } if nums1Mid == len(nums1) { midRight = nums2[nums2Mid] } else if nums2Mid == len(nums2) { midRight = nums1[nums1Mid] } else { midRight = min(nums1[nums1Mid], nums2[nums2Mid]) } return float64(midLeft+midRight) / 2 }  ⬅️上一页\n下一页➡️\n "}),a.add({id:5,href:'/leetcode-js/ChapterOne/0001~0099/0005.Longest-Palindromic-Substring/',title:"0005. Longest Palindromic Substring",section:"0001 0099",content:"5. Longest Palindromic Substring #  题目 #  Given a string s, return the longest palindromic substring in s.\nExample 1:\nInput: s = \u0026quot;babad\u0026quot; Output: \u0026quot;bab\u0026quot; Note: \u0026quot;aba\u0026quot; is also a valid answer. Example 2:\nInput: s = \u0026quot;cbbd\u0026quot; Output: \u0026quot;bb\u0026quot; Example 3:\nInput: s = \u0026quot;a\u0026quot; Output: \u0026quot;a\u0026quot; Example 4:\nInput: s = \u0026quot;ac\u0026quot; Output: \u0026quot;a\u0026quot; Constraints:\n 1 \u0026lt;= s.length \u0026lt;= 1000 s consist of only digits and English letters (lower-case and/or upper-case),  题目大意 #  给你一个字符串 s，找到 s 中最长的回文子串。\n解题思路 #    此题非常经典，并且有多种解法。\n  解法一，动态规划。定义 dp[i][j] 表示从字符串第 i 个字符到第 j 个字符这一段子串是否是回文串。由回文串的性质可以得知，回文串去掉一头一尾相同的字符以后，剩下的还是回文串。所以状态转移方程是 dp[i][j] = (s[i] == s[j]) \u0026amp;\u0026amp; ((j-i \u0026lt; 3) || dp[i+1][j-1])，注意特殊的情况，j - i == 1 的时候，即只有 2 个字符的情况，只需要判断这 2 个字符是否相同即可。j - i == 2 的时候，即只有 3 个字符的情况，只需要判断除去中心以外对称的 2 个字符是否相等。每次循环动态维护保存最长回文串即可。时间复杂度 O(n^2)，空间复杂度 O(n^2)。\n  解法二，中心扩散法。动态规划的方法中，我们将任意起始，终止范围内的字符串都判断了一遍。其实没有这个必要，如果不是最长回文串，无需判断并保存结果。所以动态规划的方法在空间复杂度上还有优化空间。判断回文有一个核心问题是找到“轴心”。如果长度是偶数，那么轴心是中心虚拟的，如果长度是奇数，那么轴心正好是正中心的那个字母。中心扩散法的思想是枚举每个轴心的位置。然后做两次假设，假设最长回文串是偶数，那么以虚拟中心往 2 边扩散；假设最长回文串是奇数，那么以正中心的字符往 2 边扩散。扩散的过程就是对称判断两边字符是否相等的过程。这个方法时间复杂度和动态规划是一样的，但是空间复杂度降低了。时间复杂度 O(n^2)，空间复杂度 O(1)。\n  解法三，滑动窗口。这个写法其实就是中心扩散法变了一个写法。中心扩散是依次枚举每一个轴心。滑动窗口的方法稍微优化了一点，有些轴心两边字符不相等，下次就不会枚举这些不可能形成回文子串的轴心了。不过这点优化并没有优化时间复杂度，时间复杂度 O(n^2)，空间复杂度 O(1)。\n  解法四，马拉车算法。这个算法是本题的最优解，也是最复杂的解法。时间复杂度 O(n)，空间复杂度 O(n)。中心扩散法有 2 处有重复判断，第一处是每次都往两边扩散，不同中心扩散多次，实际上有很多重复判断的字符，能否不重复判断？第二处，中心能否跳跃选择，不是每次都枚举，是否可以利用前一次的信息，跳跃选择下一次的中心？马拉车算法针对重复判断的问题做了优化，增加了一个辅助数组，将时间复杂度从 O(n^2) 优化到了 O(n)，空间换了时间，空间复杂度增加到 O(n)。\n   首先是预处理，向字符串的头尾以及每两个字符中间添加一个特殊字符 #，比如字符串 aaba 处理后会变成 #a#a#b#a#。那么原先长度为偶数的回文字符串 aa 会变成长度为奇数的回文字符串 #a#a#，而长度为奇数的回文字符串 aba 会变成长度仍然为奇数的回文字符串 #a#b#a#，经过预处理以后，都会变成长度为奇数的字符串。**注意这里的特殊字符不需要是没有出现过的字母，也可以使用任何一个字符来作为这个特殊字符。**这是因为，当我们只考虑长度为奇数的回文字符串时，每次我们比较的两个字符奇偶性一定是相同的，所以原来字符串中的字符不会与插入的特殊字符互相比较，不会因此产生问题。**预处理以后，以某个中心扩散的步数和实际字符串长度是相等的。**因为半径里面包含了插入的特殊字符，又由于左右对称的性质，所以扩散半径就等于原来回文子串的长度。\n   核心部分是如何通过左边已经扫描过的数据推出右边下一次要扩散的中心。这里定义下一次要扩散的中心下标是 i。如果 i 比 maxRight 要小，只能继续中心扩散。如果 i 比 maxRight 大，这是又分为 3 种情况。三种情况见上图。将上述 3 种情况总结起来，就是 ：dp[i] = min(maxRight-i, dp[2*center-i])，其中，mirror 相对于 center 是和 i 中心对称的，所以它的下标可以计算出来是 2*center-i。更新完 dp[i] 以后，就要进行中心扩散了。中心扩散以后动态维护最长回文串并相应的更新 center，maxRight，并且记录下原始字符串的起始位置 begin 和 maxLen。\n  代码 #  package leetcode // 解法一 Manacher\u0026#39;s algorithm，时间复杂度 O(n)，空间复杂度 O(n) func longestPalindrome(s string) string { if len(s) \u0026lt; 2 { return s } newS := make([]rune, 0) newS = append(newS, \u0026#39;#\u0026#39;) for _, c := range s { newS = append(newS, c) newS = append(newS, \u0026#39;#\u0026#39;) } // dp[i]: 以预处理字符串下标 i 为中心的回文半径(奇数长度时不包括中心) 	// maxRight: 通过中心扩散的方式能够扩散的最右边的下标 	// center: 与 maxRight 对应的中心字符的下标 	// maxLen: 记录最长回文串的半径 	// begin: 记录最长回文串在起始串 s 中的起始下标 	dp, maxRight, center, maxLen, begin := make([]int, len(newS)), 0, 0, 1, 0 for i := 0; i \u0026lt; len(newS); i++ { if i \u0026lt; maxRight { // 这一行代码是 Manacher 算法的关键所在 	dp[i] = min(maxRight-i, dp[2*center-i]) } // 中心扩散法更新 dp[i] 	left, right := i-(1+dp[i]), i+(1+dp[i]) for left \u0026gt;= 0 \u0026amp;\u0026amp; right \u0026lt; len(newS) \u0026amp;\u0026amp; newS[left] == newS[right] { dp[i]++ left-- right++ } // 更新 maxRight，它是遍历过的 i 的 i + dp[i] 的最大者 	if i+dp[i] \u0026gt; maxRight { maxRight = i + dp[i] center = i } // 记录最长回文子串的长度和相应它在原始字符串中的起点 	if dp[i] \u0026gt; maxLen { maxLen = dp[i] begin = (i - maxLen) / 2 // 这里要除以 2 因为有我们插入的辅助字符 # 	} } return s[begin : begin+maxLen] } func min(x, y int) int { if x \u0026lt; y { return x } return y } // 解法二 滑动窗口，时间复杂度 O(n^2)，空间复杂度 O(1) func longestPalindrome1(s string) string { if len(s) == 0 { return \u0026#34;\u0026#34; } left, right, pl, pr := 0, -1, 0, 0 for left \u0026lt; len(s) { // 移动到相同字母的最右边（如果有相同字母） 	for right+1 \u0026lt; len(s) \u0026amp;\u0026amp; s[left] == s[right+1] { right++ } // 找到回文的边界 	for left-1 \u0026gt;= 0 \u0026amp;\u0026amp; right+1 \u0026lt; len(s) \u0026amp;\u0026amp; s[left-1] == s[right+1] { left-- right++ } if right-left \u0026gt; pr-pl { pl, pr = left, right } // 重置到下一次寻找回文的中心 	left = (left+right)/2 + 1 right = left } return s[pl : pr+1] } // 解法三 中心扩散法，时间复杂度 O(n^2)，空间复杂度 O(1) func longestPalindrome2(s string) string { res := \u0026#34;\u0026#34; for i := 0; i \u0026lt; len(s); i++ { res = maxPalindrome(s, i, i, res) res = maxPalindrome(s, i, i+1, res) } return res } func maxPalindrome(s string, i, j int, res string) string { sub := \u0026#34;\u0026#34; for i \u0026gt;= 0 \u0026amp;\u0026amp; j \u0026lt; len(s) \u0026amp;\u0026amp; s[i] == s[j] { sub = s[i : j+1] i-- j++ } if len(res) \u0026lt; len(sub) { return sub } return res } // 解法四 DP，时间复杂度 O(n^2)，空间复杂度 O(n^2) func longestPalindrome3(s string) string { res, dp := \u0026#34;\u0026#34;, make([][]bool, len(s)) for i := 0; i \u0026lt; len(s); i++ { dp[i] = make([]bool, len(s)) } for i := len(s) - 1; i \u0026gt;= 0; i-- { for j := i; j \u0026lt; len(s); j++ { dp[i][j] = (s[i] == s[j]) \u0026amp;\u0026amp; ((j-i \u0026lt; 3) || dp[i+1][j-1]) if dp[i][j] \u0026amp;\u0026amp; (res == \u0026#34;\u0026#34; || j-i+1 \u0026gt; len(res)) { res = s[i : j+1] } } } return res }  ⬅️上一页\n下一页➡️\n "}),a.add({id:6,href:'/leetcode-js/ChapterOne/0001~0099/0006.ZigZag-Conversion/',title:"0006. Zig Zag Conversion",section:"0001 0099",content:"6. ZigZag Conversion #  题目 #  The string \u0026quot;PAYPALISHIRING\u0026quot; is written in a zigzag pattern on a given number of rows like this: (you may want to display this pattern in a fixed font for better legibility)\nP A H N A P L S I I G Y I R And then read line by line: \u0026quot;PAHNAPLSIIGYIR\u0026quot;\nWrite the code that will take a string and make this conversion given a number of rows:\nstring convert(string s, int numRows); Example 1:\nInput: s = \u0026quot;PAYPALISHIRING\u0026quot;, numRows = 3 Output: \u0026quot;PAHNAPLSIIGYIR\u0026quot; Example 2:\nInput: s = \u0026quot;PAYPALISHIRING\u0026quot;, numRows = 4 Output: \u0026quot;PINALSIGYAHRPI\u0026quot; Explanation: P I N A L S I G Y A H R P I Example 3:\nInput: s = \u0026quot;A\u0026quot;, numRows = 1 Output: \u0026quot;A\u0026quot; Constraints:\n 1 \u0026lt;= s.length \u0026lt;= 1000 s consists of English letters (lower-case and upper-case), ',' and '.'. 1 \u0026lt;= numRows \u0026lt;= 1000  题目大意 #  将一个给定字符串 s 根据给定的行数 numRows ，以从上往下、从左到右进行 Z 字形排列。\n比如输入字符串为 \u0026quot;PAYPALISHIRING\u0026quot; 行数为 3 时，排列如下：\nP A H N A P L S I I G Y I R 之后，你的输出需要从左往右逐行读取，产生出一个新的字符串，比如：\u0026quot;PAHNAPLSIIGYIR\u0026quot;。\n请你实现这个将字符串进行指定行数变换的函数：\nstring convert(string s, int numRows); 解题思路 #   这一题没有什么算法思想，考察的是对程序控制的能力。用 2 个变量保存方向，当垂直输出的行数达到了规定的目标行数以后，需要从下往上转折到第一行，循环中控制好方向ji  代码 #  package leetcode func convert(s string, numRows int) string { matrix, down, up := make([][]byte, numRows, numRows), 0, numRows-2 for i := 0; i != len(s); { if down != numRows { matrix[down] = append(matrix[down], byte(s[i])) down++ i++ } else if up \u0026gt; 0 { matrix[up] = append(matrix[up], byte(s[i])) up-- i++ } else { up = numRows - 2 down = 0 } } solution := make([]byte, 0, len(s)) for _, row := range matrix { for _, item := range row { solution = append(solution, item) } } return string(solution) }  ⬅️上一页\n下一页➡️\n "}),a.add({id:7,href:'/leetcode-js/ChapterOne/0001~0099/0007.Reverse-Integer/',title:"0007. Reverse Integer",section:"0001 0099",content:"7. Reverse Integer #  题目 #  Given a 32-bit signed integer, reverse digits of an integer.\nExample 1:\nInput: 123 Output: 321  Example 2:\nInput: -123 Output: -321  Example 3:\nInput: 120 Output: 21  Note: Assume we are dealing with an environment which could only store integers within the 32-bit signed integer range: [−2^31, 2^31 − 1]. For the purpose of this problem, assume that your function returns 0 when the reversed integer overflows.\n题目大意 #  给出一个 32 位的有符号整数，你需要将这个整数中每位上的数字进行反转。注意:假设我们的环境只能存储得下 32 位的有符号整数，则其数值范围为 [−2^31, 2^31 − 1]。请根据这个假设，如果反转后整数溢出那么就返回 0。\n解题思路 #   这一题是简单题，要求反转 10 进制数。类似的题目有第 190 题。 这一题只需要注意一点，反转以后的数字要求在 [−2^31, 2^31 − 1]范围内，超过这个范围的数字都要输出 0 。  代码 #  package leetcode func reverse7(x int) int { tmp := 0 for x != 0 { tmp = tmp*10 + x%10 x = x / 10 } if tmp \u0026gt; 1\u0026lt;\u0026lt;31-1 || tmp \u0026lt; -(1\u0026lt;\u0026lt;31) { return 0 } return tmp }  ⬅️上一页\n下一页➡️\n "}),a.add({id:8,href:'/leetcode-js/ChapterOne/0001~0099/0008.String-to-Integer-atoi/',title:"0008. String to Integer Atoi",section:"0001 0099",content:"8. String to Integer (atoi) #  题目 #  Implement the myAtoi(string s) function, which converts a string to a 32-bit signed integer (similar to C/C++\u0026lsquo;s atoi function).\nThe algorithm for myAtoi(string s) is as follows:\n Read in and ignore any leading whitespace. Check if the next character (if not already at the end of the string) is '-' or '+'. Read this character in if it is either. This determines if the final result is negative or positive respectively. Assume the result is positive if neither is present. Read in next the characters until the next non-digit charcter or the end of the input is reached. The rest of the string is ignored. Convert these digits into an integer (i.e. \u0026quot;123\u0026quot; -\u0026gt; 123, \u0026quot;0032\u0026quot; -\u0026gt; 32). If no digits were read, then the integer is 0. Change the sign as necessary (from step 2). If the integer is out of the 32-bit signed integer range [-231, 231 - 1], then clamp the integer so that it remains in the range. Specifically, integers less than 231 should be clamped to 231, and integers greater than 231 - 1 should be clamped to 231 - 1. Return the integer as the final result.  Note:\n Only the space character ' ' is considered a whitespace character. Do not ignore any characters other than the leading whitespace or the rest of the string after the digits.  Example 1:\nInput: s = \u0026quot;42\u0026quot; Output: 42 Explanation: The underlined characters are what is read in, the caret is the current reader position. Step 1: \u0026quot;42\u0026quot; (no characters read because there is no leading whitespace) ^ Step 2: \u0026quot;42\u0026quot; (no characters read because there is neither a '-' nor '+') ^ Step 3: \u0026quot;42\u0026quot; (\u0026quot;42\u0026quot; is read in) ^ The parsed integer is 42. Since 42 is in the range [-231, 231 - 1], the final result is 42. Example 2:\nInput: s = \u0026quot; -42\u0026quot; Output: -42 Explanation: Step 1: \u0026quot; -42\u0026quot; (leading whitespace is read and ignored) ^ Step 2: \u0026quot; -42\u0026quot; ('-' is read, so the result should be negative) ^ Step 3: \u0026quot; -42\u0026quot; (\u0026quot;42\u0026quot; is read in) ^ The parsed integer is -42. Since -42 is in the range [-231, 231 - 1], the final result is -42. Example 3:\nInput: s = \u0026quot;4193 with words\u0026quot; Output: 4193 Explanation: Step 1: \u0026quot;4193 with words\u0026quot; (no characters read because there is no leading whitespace) ^ Step 2: \u0026quot;4193 with words\u0026quot; (no characters read because there is neither a '-' nor '+') ^ Step 3: \u0026quot;4193 with words\u0026quot; (\u0026quot;4193\u0026quot; is read in; reading stops because the next character is a non-digit) ^ The parsed integer is 4193. Since 4193 is in the range [-231, 231 - 1], the final result is 4193. Example 4:\nInput: s = \u0026quot;words and 987\u0026quot; Output: 0 Explanation: Step 1: \u0026quot;words and 987\u0026quot; (no characters read because there is no leading whitespace) ^ Step 2: \u0026quot;words and 987\u0026quot; (no characters read because there is neither a '-' nor '+') ^ Step 3: \u0026quot;words and 987\u0026quot; (reading stops immediately because there is a non-digit 'w') ^ The parsed integer is 0 because no digits were read. Since 0 is in the range [-231, 231 - 1], the final result is 0. Example 5:\nInput: s = \u0026quot;-91283472332\u0026quot; Output: -2147483648 Explanation: Step 1: \u0026quot;-91283472332\u0026quot; (no characters read because there is no leading whitespace) ^ Step 2: \u0026quot;-91283472332\u0026quot; ('-' is read, so the result should be negative) ^ Step 3: \u0026quot;-91283472332\u0026quot; (\u0026quot;91283472332\u0026quot; is read in) ^ The parsed integer is -91283472332. Since -91283472332 is less than the lower bound of the range [-231, 231 - 1], the final result is clamped to -231 = -2147483648. Constraints:\n 0 \u0026lt;= s.length \u0026lt;= 200 s consists of English letters (lower-case and upper-case), digits (0-9), ' ', '+'  题目大意 #  请你来实现一个 myAtoi(string s) 函数，使其能将字符串转换成一个 32 位有符号整数（类似 C/C++ 中的 atoi 函数）。\n函数 myAtoi(string s) 的算法如下：\n 读入字符串并丢弃无用的前导空格 检查下一个字符（假设还未到字符末尾）为正还是负号，读取该字符（如果有）。 确定最终结果是负数还是正数。 如果两者都不存在，则假定结果为正。 读入下一个字符，直到到达下一个非数字字符或到达输入的结尾。字符串的其余部分将被忽略。 将前面步骤读入的这些数字转换为整数（即，\u0026ldquo;123\u0026rdquo; -\u0026gt; 123， \u0026ldquo;0032\u0026rdquo; -\u0026gt; 32）。如果没有读入数字，则整数为 0 。必要时更改符号（从步骤 2 开始）。 如果整数数超过 32 位有符号整数范围 [−231, 231 − 1] ，需要截断这个整数，使其保持在这个范围内。具体来说，小于 −231 的整数应该被固定为 −231 ，大于 231 − 1 的整数应该被固定为 231 − 1 。 返回整数作为最终结果。  注意：\n 本题中的空白字符只包括空格字符 ' ' 。 除前导空格或数字后的其余字符串外，请勿忽略 任何其他字符。  解题思路 #   这题是简单题。题目要求实现类似 C++ 中 atoi 函数的功能。这个函数功能是将字符串类型的数字转成 int 类型数字。先去除字符串中的前导空格，并判断记录数字的符号。数字需要去掉前导 0 。最后将数字转换成数字类型，判断是否超过 int 类型的上限 [-2^31, 2^31 - 1]，如果超过上限，需要输出边界，即 -2^31，或者 2^31 - 1。  代码 #  package leetcode func myAtoi(s string) int { maxInt, signAllowed, whitespaceAllowed, sign, digits := int64(2\u0026lt;\u0026lt;30), true, true, 1, []int{} for _, c := range s { if c == \u0026#39; \u0026#39; \u0026amp;\u0026amp; whitespaceAllowed { continue } if signAllowed { if c == \u0026#39;+\u0026#39; { signAllowed = false whitespaceAllowed = false continue } else if c == \u0026#39;-\u0026#39; { sign = -1 signAllowed = false whitespaceAllowed = false continue } } if c \u0026lt; \u0026#39;0\u0026#39; || c \u0026gt; \u0026#39;9\u0026#39; { break } whitespaceAllowed, signAllowed = false, false digits = append(digits, int(c-48)) } var num, place int64 place, num = 1, 0 lastLeading0Index := -1 for i, d := range digits { if d == 0 { lastLeading0Index = i } else { break } } if lastLeading0Index \u0026gt; -1 { digits = digits[lastLeading0Index+1:] } var rtnMax int64 if sign \u0026gt; 0 { rtnMax = maxInt - 1 } else { rtnMax = maxInt } digitsCount := len(digits) for i := digitsCount - 1; i \u0026gt;= 0; i-- { num += int64(digits[i]) * place place *= 10 if digitsCount-i \u0026gt; 10 || num \u0026gt; rtnMax { return int(int64(sign) * rtnMax) } } num *= int64(sign) return int(num) }  ⬅️上一页\n下一页➡️\n "}),a.add({id:9,href:'/leetcode-js/ChapterOne/0001~0099/0009.Palindrome-Number/',title:"0009. Palindrome Number",section:"0001 0099",content:"9. Palindrome Number #  题目 #  Determine whether an integer is a palindrome. An integer is a palindrome when it reads the same backward as forward.\nExample 1:\nInput: 121 Output: true Example 2:\nInput: -121 Output: false Explanation: From left to right, it reads -121. From right to left, it becomes 121-. Therefore it is not a palindrome. Example 3:\nInput: 10 Output: false Explanation: Reads 01 from right to left. Therefore it is not a palindrome. Follow up:\nCoud you solve it without converting the integer to a string?\n题目大意 #  判断一个整数是否是回文数。回文数是指正序（从左向右）和倒序（从右向左）读都是一样的整数。\n解题思路 #   判断一个整数是不是回文数。 简单题。注意会有负数的情况，负数，个位数，10 都不是回文数。其他的整数再按照回文的规则判断。  代码 #  package leetcode import \u0026#34;strconv\u0026#34; // 解法一 func isPalindrome(x int) bool { if x \u0026lt; 0 { return false } if x == 0 { return true } if x%10 == 0 { return false } arr := make([]int, 0, 32) for x \u0026gt; 0 { arr = append(arr, x%10) x = x / 10 } sz := len(arr) for i, j := 0, sz-1; i \u0026lt;= j; i, j = i+1, j-1 { if arr[i] != arr[j] { return false } } return true } // 解法二 数字转字符串 func isPalindrome1(x int) bool { if x \u0026lt; 0 { return false } if x \u0026lt; 10 { return true } s := strconv.Itoa(x) length := len(s) for i := 0; i \u0026lt;= length/2; i++ { if s[i] != s[length-1-i] { return false } } return true }  ⬅️上一页\n下一页➡️\n "}),a.add({id:10,href:'/leetcode-js/ChapterOne/0200~0299/0206.Reverse-Linked-List/',title:"0206. Reverse Linked List",section:"0200 0299",content:"206. Reverse Linked List #  题目 #  Reverse a singly linked list.\n题目大意 #  翻转单链表\n解题思路 #  有两种解题方法，一是循环、二是递归。\n代码 #  循环 #  /** * Definition for singly-linked list. * function ListNode(val, next) { * this.val = (val===undefined ? 0 : val) * this.next = (next===undefined ? null : next) * } */ /** * @param {ListNode} head * @return {ListNode} */ var reverseList = function(head) { let prev = null; let cur = head; while(cur !== null) { let next = cur.next; cur.next = prev; prev = cur; cur = next; } return prev; } 递归 #  /** * Definition for singly-linked list. * function ListNode(val, next) { * this.val = (val===undefined ? 0 : val) * this.next = (next===undefined ? null : next) * } */ /** * @param {ListNode} head * @return {ListNode} */ var reverseList = function(head) { if ( head === null || head.next === null) { return head; } const last = reverseList(head.next) head.next.next = head; head.next = null; return last; };  ⬅️上一页\n下一页➡️\n "})})()